select product1_id , product2_id,product1_category, product2_category , customer_count from (select product1_id , product1_category,  product2_id,category as product2_category , customer_count from(select product1_id , category as product1_category,  product2_id , customer_count from (select product1_id , product2_id  , customer_count from (select id1 product1_id ,id2 product2_id , count(*) as customer_count from (select user1 ,  user2 , id1 , id2 from (select user1 , user_id user2 , id1 , id2 from (select user_id user1, id1 , id2 from(select id1 , id2 from (select * from (select distinct product_id id1 from ProductPurchases) as dis1 join (select distinct product_id id2 from ProductPurchases) as dis2
on dis1.id1 < dis2.id2) as all_ids ) as res join ProductPurchases on res.id1 = ProductPurchases.product_id ) res2 join  ProductPurchases on res2.id2 = ProductPurchases.product_id) as res3 where user1=user2) as res4 group by product1_id , product2_id having count(*) >=3) as s where customer_count >= 3) as res_one join ProductInfo on res_one.product1_id = ProductInfo.product_id) as res_two join ProductInfo on res_two.product2_id = ProductInfo.product_id ) as final_res order by customer_count DESC , product1_id , product2_id;
